#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <fstream>
#include <cstdio> // For popen/pclose

std::string run_user_program(const std::string& input_str) {
    std::string command = "./a.out";
    #ifdef _WIN32
        command = "program.exe";
    #endif

    std::string input_filename = "temp_input.txt";
    std::ofstream input_file(input_filename);
    input_file << input_str;
    input_file.close();

    command += " < " + input_filename;

    FILE* pipe = popen(command.c_str(), "r");
    if (!pipe) {
        return "Error: Could not open pipe to execute program.";
    }

    char buffer[128];
    std::string result = "";
    int max_lines = 20; 
    int current_lines = 0;
    while (fgets(buffer, sizeof(buffer), pipe) != nullptr && current_lines < max_lines) {
        result += buffer;
        if (std::string(buffer).find('\n') != std::string::npos) {
            current_lines++;
        }
    }
    if (!feof(pipe)) { 
        result += "... (output truncated due to potential infinite loop)";
    }

    pclose(pipe);
    remove(input_filename.c_str());
    return result;
}
